### Step 1: Define the Board Class

The `Board` class will represent the 8x8 checkers board and manage the pieces' positions.

```python
class Board:
    def __init__(self):
        self.board = []
        self.initialize_board()

    def initialize_board(self):
        # Initialize an 8x8 board with alternating positions for black and red pieces
        for row in range(8):
            if row % 2 == 0:
                self.board.append(['R' if col % 2 != 0 else '.' for col in range(8)])
            else:
                self.board.append(['B' if col % 2 == 0 else '.' for col in range(8)])

    def print_board(self):
        # Print the board with row and column indices
        for i, row in enumerate(self.board):
            print(f"{i}: {' '.join(row)}")

    def get_piece(self, row, col):
        return self.board[row][col]

    def set_piece(self, row, col, piece):
        self.board[row][col] = piece

    def is_valid_move(self, from_row, from_col, to_row, to_col):
        # Check if the move is within bounds and follows standard checkers rules
        if not (0 <= from_row < 8 and 0 <= from_col < 8 and 0 <= to_row < 8 and 0 <= to_col < 8):
            return False

        piece = self.get_piece(from_row, from_col)
        opponent = 'B' if piece == 'R' else 'R'

        # Single jump
        if abs(from_row - to_row) == 1 and abs(from_col - to_col) == 1:
            if self.get_piece(to_row, to_col) == '.':
                return True

        # Multiple jumps (double jumps)
        elif abs(from_row - to_row) == 2 and abs(from_col - to_col) == 2:
            intermediate_row = (from_row + to_row) // 2
            intermediate_col = (from_col + to_col) // 2
            if self.get_piece(intermediate_row, intermediate_col) == opponent and self.get_piece(to_row, to_col) == '.':
                return True

        return False

    def make_move(self, from_row, from_col, to_row, to_col):
        # Move the piece and capture opponent's piece if any
        piece = self.get_piece(from_row, from_col)
        self.set_piece(to_row, to_col, piece)
        self.set_piece(from_row, from_col, '.')

        intermediate_row = (from_row + to_row) // 2
        intermediate_col = (from_col + to_col) // 2
        if self.get_piece(intermediate_row, intermediate_col) != '.':
            self.set_piece(intermediate_row, intermediate_col, '.')

    def is_game_over(self):
        # Check for game over conditions: no legal moves or stalemate
        return True

    def get_all_pieces(self, color):
        pieces = []
        for row in range(8):
            for col in range(8):
                if self.get_piece(row, col) == color:
                    pieces.append((row, col))
        return pieces

```

### Step 2: Define the Player Class

The `Player` class will handle player input and manage their moves.

```python
class Player:
    def __init__(self, color):
        self.color = color

    def make_move(self, board):
        # Prompt player for move input in "from-to" notation
        while True:
            try:
                from_pos = input(f"{self.color}'s turn. Enter move (e.g., 3-4): ")
                from_row, from_col = map(int, from_pos.split('-'))
                to_row, to_col = int(input("Enter destination: ")), int(input())

                if board.is_valid_move(from_row, from_col, to_row, to_col):
                    board.make_move(from_row, from_col, to_row, to_col)
                    break
                else:
                    print("Invalid move. Please try again.")
            except ValueError:
                print("Invalid input. Please enter numbers separated by a hyphen.")

```

### Step 3: Define the Game Loop

The game loop will control the flow of the game.

```python
def main():
    board = Board()
    player1 = Player('R')
    player2 = Player('B')
    current_player = player1

    while not board.is_game_over():
        board.print_board()
        if isinstance(current_player, Player):
            current_player.make_move(board)
        else:
            # AI logic can be implemented here
            pass

        # Switch turns
        current_player = player2 if current_player == player1 else player1

    board.print_board()
    print("Game over!")

if __name__ == "__main__":
    main()
```

